#include <bits/stdc++.h>
using namespace std;
int main()
{
    int n,num[1005];
    cin>>n;
    long a[1005];
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i];
        num[i]=i+1;
    }
    for(int i=1;i<=n-1;i++)
    {
        for(int j=0;j<=n-i-1;j++)
        {
            if(a[j]>a[j+1])
            {
                swap(a[j],a[j+1]);
                swap(num[j],num[j+1]);
            }
        }
    }
    for(int i=0;i<=n-1;i++)
    {
        cout<<num[i]<<" ";
    }
    cout<<endl;
    double b=0;
    for(int i=0;i<=n-1;i++)
    {
        b+=a[i]*(n-1-i);
    }
    printf("%.2lf",b/n);
    return 0;
}
